import './results.css';
// Here we are passing in the object we want as props and deconstructing it. 
// We do need an Id for each row but that is in the calling code where we are .Map the array
// <ResultsRow key={fixture.Id} {fixture=h}
const ResultsRow = ({fixture, viewFixture} : any) => {
    
    const result = fixture.result === "W" ? "table-success" : "table-danger";
    
    return(             
        <tr onClick={() => viewFixture(fixture)}>
            <td>{fixture.date}</td>
            <td className={result}>{fixture.result}</td>
            <td>{fixture.homeTeam}</td>
            <td>{fixture.homeScore}</td>                        
            <td>{fixture.awayScore}</td>
            <td>{fixture.awayTeam}</td>
            <td>{fixture.fixture}</td>
        </tr>
    )
}               
export default ResultsRow;
